//! Phenotype Forge - Task runner for the Phenotype ecosystem
//!
//! A Rust-native task runner with parallel execution, dependency graph resolution,
//! hot reload, and a powerful plugin system for build automation.

use std::collections::HashMap;

/// Task definition for the forge task runner
#[derive(Debug, Clone)]
pub struct Task {
    pub name: String,
    pub command: String,
    pub deps: Vec<String>,
    pub env: HashMap<String, String>,
    pub working_dir: Option<String>,
}

impl Task {
    /// Create a new task with the given name and command
    pub fn new(name: impl Into<String>, command: impl Into<String>) -> Self {
        Self {
            name: name.into(),
            command: command.into(),
            deps: Vec::new(),
            env: HashMap::new(),
            working_dir: None,
        }
    }

    /// Add a dependency to this task
    pub fn with_dep(mut self, dep: impl Into<String>) -> Self {
        self.deps.push(dep.into());
        self
    }

    /// Add an environment variable
    pub fn with_env(mut self, key: impl Into<String>, value: impl Into<String>) -> Self {
        self.env.insert(key.into(), value.into());
        self
    }

    /// Set the working directory
    pub fn with_working_dir(mut self, dir: impl Into<String>) -> Self {
        self.working_dir = Some(dir.into());
        self
    }

    /// Check if this task has all required fields
    pub fn is_valid(&self) -> bool {
        !self.name.is_empty() && !self.command.is_empty()
    }
}

/// Parse tasks from TOML configuration
pub fn parse_tasks(config: &str) -> Result<HashMap<String, Task>, toml::de::Error> {
    let table: toml::Table = toml::from_str(config)?;
    let mut tasks = HashMap::new();

    if let Some(tasks_table) = table.get("tasks").and_then(|t| t.as_table()) {
        for (name, value) in tasks_table {
            if let Some(task_table) = value.as_table() {
                let command = task_table
                    .get("command")
                    .and_then(|c| c.as_str())
                    .unwrap_or("")
                    .to_string();

                let deps: Vec<String> = task_table
                    .get("deps")
                    .and_then(|d| d.as_array())
                    .map(|arr| {
                        arr.iter()
                            .filter_map(|v| v.as_str().map(String::from))
                            .collect()
                    })
                    .unwrap_or_default();

                let env: HashMap<String, String> = task_table
                    .get("env")
                    .and_then(|e| e.as_table())
                    .map(|t| {
                        t.iter()
                            .filter_map(|(k, v)| v.as_str().map(|s| (k.clone(), s.to_string())))
                            .collect()
                    })
                    .unwrap_or_default();

                let working_dir = task_table
                    .get("working_dir")
                    .and_then(|w| w.as_str())
                    .map(String::from);

                tasks.insert(
                    name.clone(),
                    Task {
                        name: name.clone(),
                        command,
                        deps,
                        env,
                        working_dir,
                    },
                );
            }
        }
    }

    Ok(tasks)
}

/// Detect if a dependency graph has cycles
pub fn has_cyclic_dependency(tasks: &HashMap<String, Task>) -> Option<Vec<String>> {
    fn visit(
        task_name: &str,
        tasks: &HashMap<String, Task>,
        visited: &mut HashMap<String, bool>,
        path: &mut Vec<String>,
    ) -> Option<Vec<String>> {
        if let Some(&true) = visited.get(task_name) {
            return None; // Already verified as acyclic
        }

        if let Some(&false) = visited.get(task_name) {
            // Found a cycle - return the cycle path
            let cycle_start = path.iter().position(|p| p == task_name).unwrap_or(0);
            return Some(path[cycle_start..].to_vec());
        }

        // Mark as being visited (in current path)
        visited.insert(task_name.to_string(), false);
        path.push(task_name.to_string());

        if let Some(task) = tasks.get(task_name) {
            for dep in &task.deps {
                if let Some(cycle) = visit(dep, tasks, visited, path) {
                    return Some(cycle);
                }
            }
        }

        path.pop();
        // Mark as fully visited and verified acyclic
        visited.insert(task_name.to_string(), true);
        None
    }

    let mut visited = HashMap::new();
    for name in tasks.keys() {
        let mut path = Vec::new();
        if let Some(cycle) = visit(name, tasks, &mut visited, &mut path) {
            return Some(cycle);
        }
    }
    None
}

/// Get tasks in dependency order (topological sort)
pub fn get_execution_order(tasks: &HashMap<String, Task>) -> Result<Vec<String>, String> {
    if let Some(cycle) = has_cyclic_dependency(tasks) {
        return Err(format!("Dependency cycle detected: {:?}", cycle));
    }

    let mut in_degree: HashMap<String, usize> = tasks
        .keys()
        .map(|k| (k.clone(), 0))
        .collect();

    // Calculate in-degrees
    for task in tasks.values() {
        for dep in &task.deps {
            if tasks.contains_key(dep) {
                *in_degree.get_mut(&task.name).unwrap() += 1;
            }
        }
    }

    // Find all tasks with no dependencies
    let mut queue: Vec<String> = in_degree
        .iter()
        .filter(|(_, &degree)| degree == 0)
        .map(|(name, _)| name.clone())
        .collect();

    let mut result = Vec::new();

    while let Some(current) = queue.pop() {
        result.push(current.clone());

        // Find tasks that depend on current and reduce their in-degree
        for task in tasks.values() {
            if task.deps.contains(&current) {
                let degree = in_degree.get_mut(&task.name).unwrap();
                *degree -= 1;
                if *degree == 0 {
                    queue.push(task.name.clone());
                }
            }
        }
    }

    if result.len() != tasks.len() {
        return Err("Could not resolve all dependencies".to_string());
    }

    Ok(result)
}

