// Traces to: FR-FORGE-005
#[test]
fn test_cyclic_dependency_detection() {
    let mut graph: HashMap<&str, Vec<&str>> = HashMap::new();
    graph.insert("a", vec!["b"]);
    graph.insert("b", vec!["a"]);

    // Check for cycle: a -> b -> a
    let mut visited: std::collections::HashSet<String> = std::collections::HashSet::new();
    let mut rec_stack: std::collections::HashSet<String> = std::collections::HashSet::new();

    fn has_cycle(
        node: &str,
        graph: &HashMap<&str, Vec<&str>>,
        visited: &mut std::collections::HashSet<String>,
        rec_stack: &mut std::collections::HashSet<String>,
    ) -> bool {
        if rec_stack.contains(node) {
            return true;
        }
        if visited.contains(node) {
            return false;
        }

        visited.insert(node.to_string());
        rec_stack.insert(node.to_string());

        if let Some(deps) = graph.get(node) {
            for dep in deps {
                if has_cycle(dep, graph, visited, rec_stack) {
                    return true;
                }
            }
        }

        rec_stack.remove(node);
        false
    }

    assert!(has_cycle("a", &graph, &mut visited, &mut rec_stack));
}

